// Time:  O(m + n)
// Space: O(1)

class Solution {
public:
    string gcdOfStrings(string str1, string str2) {
        if (str1.empty() || str2.empty()) {
            return "";
        }
        int c = gcd(str1.length(), str2.length());
        const auto& result = str1.substr(0, c);
        return check(str1, result) && check(str2, result) ? result : "";
    }

private:
    bool check(const string& s, const string& common) {
        int i = 0;
        for (const auto& c : s) {
            if (c != common[i]) {
                return false;
            }
            i = (i + 1) % common.length();
        }
        return true;
    }

    int gcd(int a, int b) {
        while (b != 0) {
            int tmp = b;
            b = a % b;
            a = tmp;
        }
        return a;
    }
};

# Time:  O(m + n)
# Space: O(1)

class Solution(object):
    def gcdOfStrings(self, str1, str2):
        """
        :type str1: str
        :type str2: str
        :rtype: str
        """
        def check(s, common):
            i = 0
            for c in s:
                if c != common[i]:
                    return False
                i = (i+1)%len(common)
            return True

        def gcd(a, b):  # Time: O(log(min(a, b)))
            while b:
                a, b = b, a % b
            return a

        if not str1 or not str2:
            return ""
        c = gcd(len(str1), len(str2))
        result = str1[:c]
        return result if check(str1, result) and check(str2, result) else ""
